import numpy as np
from typing import List, Dict, Tuple, Callable
from dataclasses import dataclass

@dataclass
class Period:
    name: str
    start: int
    end: int
    period_type: str

class WalkForwardValidator:
    def __init__(self, train_size: int, test_size: int, n_periods: int):
        self.train_size = train_size
        self.test_size = test_size
        self.n_periods = n_periods

    def create_periods(self, data_length: int) -> List[Period]:
        periods = []

        for i in range(self.n_periods):
            train_start = i * self.test_size
            train_end = train_start + self.train_size
            test_start = train_end
            test_end = test_start + self.test_size

            if test_end > data_length:
                break

            periods.append(Period(
                name=f"train_{i+1}",
                start=train_start,
                end=train_end,
                period_type="train"
            ))

            periods.append(Period(
                name=f"test_{i+1}",
                start=test_start,
                end=test_end,
                period_type="test"
            ))

        return periods

    def run_validation(self, 
                       returns: np.ndarray,
                       strategy_fn: Callable[[np.ndarray], np.ndarray]) -> Dict:
        periods = self.create_periods(len(returns))

        results = {
            "periods": [],
            "train_returns": [],
            "test_returns": []
        }

        for period in periods:
            period_returns = returns[period.start:period.end]
            strategy_returns = strategy_fn(period_returns)
            total_return = np.sum(strategy_returns) * 100

            results["periods"].append({
                "name": period.name,
                "type": period.period_type,
                "return_pct": round(total_return, 2)
            })

            if period.period_type == "train":
                results["train_returns"].append(total_return)
            else:
                results["test_returns"].append(total_return)

        # Add summary
        results["avg_train"] = np.mean(results["train_returns"]) if results["train_returns"] else 0
        results["avg_test"] = np.mean(results["test_returns"]) if results["test_returns"] else 0

        return results

    def analyze_degradation(self, results: Dict) -> Dict:
        avg_train = results.get("avg_train", 0)
        avg_test = results.get("avg_test", 0)

        if avg_train == 0:
            degradation = 0
        else:
            degradation = (avg_train - avg_test) / abs(avg_train) * 100

        return {
            "avg_train_return": round(avg_train, 2),
            "avg_test_return": round(avg_test, 2),
            "degradation_pct": round(degradation, 2),
            "is_overfit": degradation > 50,
            "recommendation": self._get_recommendation(degradation)
        }

    def _get_recommendation(self, degradation: float) -> str:
        if degradation > 80:
            return "Likely overfit. Simplify strategy."
        elif degradation > 50:
            return "Significant degradation. Review parameters."
        elif degradation > 20:
            return "Moderate degradation. Paper trade first."
        else:
            return "Acceptable. Proceed with caution."

def momentum_strategy(returns: np.ndarray) -> np.ndarray:
    positions = np.zeros(len(returns))
    lookback = 5

    for i in range(lookback, len(returns)):
        if np.sum(returns[i-lookback:i]) > 0:
            positions[i] = 1

    return positions * returns

# Test
np.random.seed(42)
returns = np.random.normal(0.0005, 0.02, 500)

validator = WalkForwardValidator(train_size=100, test_size=25, n_periods=4)
results = validator.run_validation(returns, momentum_strategy)

print("Walk-Forward Results:")
for p in results["periods"]:
    print(f"  {p['name']}: {p['return_pct']:.2f}%")

print(f"\nAvg Train: {results['avg_train']:.2f}%")
print(f"Avg Test: {results['avg_test']:.2f}%")

degradation = validator.analyze_degradation(results)
print(f"\nDegradation: {degradation['degradation_pct']:.2f}%")
print(f"Recommendation: {degradation['recommendation']}")
